import json
import boto3

def lambda_handler(event, context):
    s3_client = boto3.client('s3')
    dynamodb_client = boto3.client('dynamodb')
    sns_client = boto3.client('sns')
    sqs_client = boto3.client('sqs')
    
    # Example S3 operation
    s3_client.put_object(Bucket='your-bucket-name', Key='example.txt', Body='Hello, World!')
    
    # Example DynamoDB operation
    dynamodb_client.put_item(
        TableName='your-table-name',
        Item={
            'PrimaryKey': {'S': 'example-key'},
            'Data': {'S': 'example-data'}
        }
    )
    
    # Example SNS operation
    sns_client.publish(
        TopicArn='arn:aws:sns:your-region:your-account-id:your-topic-name',
        Message='Hello from Lambda!'
    )
    
    # Example SQS operation
    sqs_client.send_message(
        QueueUrl='https://sqs.your-region.amazonaws.com/your-account-id/your-queue-name',
        MessageBody='Hello from Lambda!'
    )
    
    return {
        'statusCode': 200,
        'body': json.dumps('Operations completed successfully')
    }